def carbon_intensity_g_per_kwh(generation_mix):
    intensity_by_source = {"solar": 40, "wind": 10, "gas": 450, "coal": 900, "nuclear": 15}
    total_kwh = sum(generation_mix.values())
    weighted_intensity = sum(
        generation_mix[source] * intensity_by_source[source] for source in generation_mix
    )
    return weighted_intensity / total_kwh

current_intensity = carbon_intensity_g_per_kwh({"solar": 3000, "gas": 2000})
